import{_ as t,c as o,o as r,ag as d}from"./chunks/framework.Bw-5EFTY.js";const u=JSON.parse('{"title":"Anthropic Specification","description":"","frontmatter":{},"headers":[],"relativePath":"packages/agent-provider-anthropic/SPEC.md","filePath":"packages/agent-provider-anthropic/SPEC.md"}'),c={name:"packages/agent-provider-anthropic/SPEC.md"};function a(s,e,i,n,p,l){return r(),o("div",null,e[0]||(e[0]=[d('<h1 id="anthropic-specification" tabindex="-1">Anthropic Specification <a class="header-anchor" href="#anthropic-specification" aria-label="Permalink to &quot;Anthropic Specification&quot;">​</a></h1><h2 id="scope" tabindex="-1">Scope <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;Scope&quot;">​</a></h2><ul><li>Owns the Anthropic Claude provider integration for Robota SDK.</li><li>Implements <code>AbstractAIProvider</code> from <code>@robota-sdk/agent-core</code> to provide Claude model access through the Anthropic Messages API.</li><li>Owns Anthropic-specific message format conversion (universal to/from Anthropic wire format).</li><li>Owns Anthropic-specific response parsing, including streaming chunk handling.</li><li>Owns Anthropic-specific tool call format conversion (<code>input_schema</code>-based tools).</li><li>Owns provider option types (<code>IAnthropicProviderOptions</code>, <code>TAnthropicProviderOptionValue</code>).</li><li>Owns Anthropic API type definitions for messages, requests, responses, streaming, tools, and errors.</li></ul><h2 id="boundaries" tabindex="-1">Boundaries <a class="header-anchor" href="#boundaries" aria-label="Permalink to &quot;Boundaries&quot;">​</a></h2><ul><li>Does not own generic agent orchestration, message types, or provider abstractions; those belong to <code>@robota-sdk/agent-core</code>.</li><li>Does not own executor contracts (<code>IExecutor</code>); imports them from <code>@robota-sdk/agent-core</code>.</li><li>Does not own <code>TUniversalMessage</code>, <code>IChatOptions</code>, <code>IToolSchema</code>, or <code>IAssistantMessage</code>; imports them from <code>@robota-sdk/agent-core</code>.</li><li>Does not implement image generation capabilities (unlike the Google provider).</li><li>Does not own session management, team collaboration, or workflow concerns.</li><li>Keeps all Anthropic-specific transport behavior explicit and provider-scoped; no leaking of Anthropic SDK types through the public API surface beyond <code>IAnthropicProviderOptions.client</code>.</li></ul><h2 id="architecture-overview" tabindex="-1">Architecture Overview <a class="header-anchor" href="#architecture-overview" aria-label="Permalink to &quot;Architecture Overview&quot;">​</a></h2><p>The package follows a provider-adapter pattern:</p><ol><li><p><strong><code>AnthropicProvider</code></strong> (<code>provider.ts</code>) -- the primary class. Extends <code>AbstractAIProvider</code> and implements <code>chat()</code>, <code>chatStream()</code>, <code>supportsTools()</code>, <code>validateConfig()</code>, and <code>dispose()</code>. Converts between <code>TUniversalMessage</code> and Anthropic <code>MessageParam</code>/<code>MessageCreateParams</code> formats. Supports both direct API execution (via <code>@anthropic-ai/sdk</code> client) and delegated execution (via <code>IExecutor</code>).</p></li><li><p><strong><code>AnthropicResponseParser</code></strong> (<code>parsers/response-parser.ts</code>) -- a static utility class that parses raw Anthropic API responses (<code>IAnthropicMessage</code>) and streaming chunks (<code>MessageStreamEvent</code>) into <code>TUniversalMessage</code>. Extracts token usage metadata and tool call data.</p></li><li><p><strong>Types layer</strong> (<code>types.ts</code>, <code>types/api-types.ts</code>) -- provider option interface and Anthropic-specific API type definitions covering messages, requests, streaming, tools, and errors.</p></li><li><p><strong>Entry point</strong> (<code>index.ts</code>) -- re-exports <code>provider.ts</code> and <code>types.ts</code>, and exposes a <code>createAnthropicProvider</code> factory function.</p></li></ol><p>Dependency direction: <code>@robota-sdk/agent-provider-anthropic</code> depends on <code>@robota-sdk/agent-core</code> (peer dependency) and <code>@anthropic-ai/sdk</code> (direct dependency). No other workspace packages are imported.</p><h2 id="type-ownership" tabindex="-1">Type Ownership <a class="header-anchor" href="#type-ownership" aria-label="Permalink to &quot;Type Ownership&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Owner</th><th>Location</th></tr></thead><tbody><tr><td><code>IAnthropicProviderOptions</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types.ts</code></td></tr><tr><td><code>TAnthropicProviderOptionValue</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types.ts</code></td></tr><tr><td><code>IAnthropicMessage</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IAnthropicContent</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IAnthropicUsage</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IAnthropicChatRequestParams</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IAnthropicStreamRequestParams</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IAnthropicRequestMessage</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IAnthropicRequestContent</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IAnthropicTool</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IAnthropicToolProperty</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IAnthropicToolCall</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IAnthropicStreamChunk</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IAnthropicStreamDelta</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IAnthropicError</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IAnthropicLogData</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IAnthropicProviderResponse</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>IAnthropicStreamContext</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/types/api-types.ts</code></td></tr><tr><td><code>AnthropicProvider</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/provider.ts</code></td></tr><tr><td><code>AnthropicResponseParser</code></td><td><code>@robota-sdk/agent-provider-anthropic</code></td><td><code>src/parsers/response-parser.ts</code></td></tr></tbody></table><p>Imported from <code>@robota-sdk/agent-core</code> (not owned): <code>AbstractAIProvider</code>, <code>TUniversalMessage</code>, <code>IChatOptions</code>, <code>IToolSchema</code>, <code>IAssistantMessage</code>, <code>IExecutor</code>, <code>TProviderOptionValueBase</code>, <code>logger</code>.</p><h2 id="public-api-surface" tabindex="-1">Public API Surface <a class="header-anchor" href="#public-api-surface" aria-label="Permalink to &quot;Public API Surface&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Kind</th><th>Source</th><th>Description</th></tr></thead><tbody><tr><td><code>AnthropicProvider</code></td><td>class</td><td><code>src/provider.ts</code></td><td>Anthropic provider implementing <code>AbstractAIProvider</code>. Methods: <code>chat()</code>, <code>chatStream()</code>, <code>supportsTools()</code>, <code>validateConfig()</code>, <code>dispose()</code>.</td></tr><tr><td><s><code>AnthropicResponseParser</code></s></td><td>class (internal)</td><td><code>src/parsers/response-parser.ts</code></td><td>Internal static utility — not exported from <code>src/index.ts</code>. Used by <code>AnthropicProvider</code> internally for response/streaming parsing.</td></tr><tr><td><code>IAnthropicProviderOptions</code></td><td>interface</td><td><code>src/types.ts</code></td><td>Configuration options for constructing <code>AnthropicProvider</code>. Fields: <code>apiKey</code>, <code>timeout</code>, <code>baseURL</code>, <code>client</code>, <code>executor</code>, plus index signature.</td></tr><tr><td><code>TAnthropicProviderOptionValue</code></td><td>type alias</td><td><code>src/types.ts</code></td><td>Union type for valid provider option values.</td></tr><tr><td><code>createAnthropicProvider</code></td><td>function (stub)</td><td><code>src/index.ts</code></td><td>Stub — currently returns <code>void</code>. Not yet implemented; placeholder for future factory pattern.</td></tr><tr><td>All types from <code>src/types/api-types.ts</code></td><td>interfaces/types</td><td><code>src/types/api-types.ts</code></td><td>Anthropic API type definitions (messages, requests, tools, streaming, errors). Exported transitively via <code>src/types.ts</code> re-export pattern.</td></tr></tbody></table><h3 id="anthropicprovider-public-instance-fields" tabindex="-1">AnthropicProvider Public Instance Fields <a class="header-anchor" href="#anthropicprovider-public-instance-fields" aria-label="Permalink to &quot;AnthropicProvider Public Instance Fields&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Field</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>enableWebTools</code></td><td><code>boolean</code></td><td><code>false</code></td><td>When true, includes <code>web_search_20250305</code> server tool in requests</td></tr><tr><td><code>onTextDelta</code></td><td><code>TTextDeltaCallback | undefined</code></td><td>—</td><td>Streaming text delta callback for real-time output</td></tr><tr><td><code>onServerToolUse</code></td><td><code>(name: string, input: Record&lt;string, string&gt;) =&gt; void</code></td><td>—</td><td>Callback when server-managed tool executes during streaming</td></tr></tbody></table><h2 id="web-search-support" tabindex="-1">Web Search Support <a class="header-anchor" href="#web-search-support" aria-label="Permalink to &quot;Web Search Support&quot;">​</a></h2><p>The provider supports Anthropic&#39;s server-side web search tool:</p><ul><li><strong><code>enableWebTools</code> flag</strong> -- When set to <code>true</code> in chat options, includes the <code>web_search_20250305</code> server tool in API requests. This is a server-managed tool (not a <code>FunctionTool</code>) that Anthropic executes during response generation.</li><li><strong><code>onServerToolUse</code> callback</strong> -- Fires when a server tool executes during streaming. The callback receives the tool name and input (e.g., query string). Consumers use this to display search status indicators.</li><li><strong>Streaming block handling</strong> -- The streaming parser handles <code>server_tool_use</code> and <code>web_search_tool_result</code> content blocks. When a <code>server_tool_use</code> block is encountered, the provider emits a search indicator (e.g., &quot;Searching...&quot;).</li><li><strong><code>formatWebSearchResults()</code></strong> -- Private method on <code>AnthropicProvider</code> that converts raw web search result blocks into human-readable text with source URLs and snippets.</li></ul><h2 id="sdk-version-and-message-format" tabindex="-1">SDK Version and Message Format <a class="header-anchor" href="#sdk-version-and-message-format" aria-label="Permalink to &quot;SDK Version and Message Format&quot;">​</a></h2><ul><li><strong>Anthropic SDK</strong>: <code>@anthropic-ai/sdk</code> v0.80.0 (upgraded from v0.24.3).</li><li><strong>System message extraction</strong>: System messages are extracted from the message array and sent via the dedicated <code>system</code> parameter in the API request, rather than being included as a <code>role: user</code> message. This follows the current Anthropic API best practice.</li><li><strong><code>chat()</code> vs <code>chatStream()</code> asymmetry</strong>: <code>chat()</code> applies <code>enableWebTools</code>, system message extraction, and <code>onServerToolUse</code> callbacks. <code>chatStream()</code> does NOT apply these features — it uses the native SDK streaming API directly without server tool support. This is a known limitation.</li><li><strong>Response parsing</strong>: Two parsing paths coexist — <code>convertFromAnthropicResponse()</code> (inline in provider, used by <code>chat()</code>) and <code>AnthropicResponseParser</code> (separate class, used by <code>chatStream()</code>). They have minor behavioral differences (e.g., <code>null</code> vs <code>&#39;&#39;</code> for tool-only content).</li><li><strong>Local API types</strong>: <code>IAnthropicStreamChunk</code> and other types in <code>api-types.ts</code> were written before migration to the native Anthropic SDK. The provider&#39;s streaming code now uses native SDK event types directly; local API types are partially unused but retained for backward compatibility.</li><li><strong><code>validateConfig()</code> edge case</strong>: Returns <code>false</code> for executor-based providers (no client/apiKey) even though the provider is functional. This is a known gap.</li></ul><h2 id="extension-points" tabindex="-1">Extension Points <a class="header-anchor" href="#extension-points" aria-label="Permalink to &quot;Extension Points&quot;">​</a></h2><ul><li><strong>Executor injection</strong>: The provider accepts an <code>IExecutor</code> via <code>IAnthropicProviderOptions.executor</code>, enabling delegation of chat operations to local or remote executors without modifying the provider.</li><li><strong>Pre-built client injection</strong>: A pre-configured <code>Anthropic</code> client instance can be passed via <code>IAnthropicProviderOptions.client</code>, allowing custom transport configuration.</li><li><strong>AbstractAIProvider contract</strong>: New lifecycle or capability methods added to <code>AbstractAIProvider</code> in <code>@robota-sdk/agent-core</code> can be overridden in <code>AnthropicProvider</code>.</li></ul><h2 id="error-taxonomy" tabindex="-1">Error Taxonomy <a class="header-anchor" href="#error-taxonomy" aria-label="Permalink to &quot;Error Taxonomy&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Error Condition</th><th>Thrown By</th><th>Message Pattern</th></tr></thead><tbody><tr><td>Missing client, apiKey, and executor</td><td><code>AnthropicProvider</code> constructor</td><td><code>&quot;Either Anthropic client, apiKey, or executor is required&quot;</code></td></tr><tr><td>Client unavailable during direct execution</td><td><code>chat()</code>, <code>chatStream()</code></td><td><code>&quot;Anthropic client not available. Either provide a client/apiKey or use an executor.&quot;</code></td></tr><tr><td>Missing model in chat options</td><td><code>chat()</code>, <code>chatStream()</code></td><td><code>&quot;Model is required in chat options. Please specify a model in defaultModel configuration.&quot;</code></td></tr><tr><td>Empty response content</td><td><code>convertFromAnthropicResponse()</code></td><td><code>&quot;No content in Anthropic response&quot;</code></td></tr><tr><td>Unsupported content block type</td><td><code>convertFromAnthropicResponse()</code></td><td><code>&quot;Unsupported content type: &lt;type&gt;&quot;</code></td></tr><tr><td>Invalid message array (not array)</td><td><code>validateMessages()</code></td><td><code>&quot;Messages must be an array&quot;</code></td></tr><tr><td>Empty message array</td><td><code>validateMessages()</code></td><td><code>&quot;Messages array cannot be empty&quot;</code></td></tr><tr><td>Invalid message role</td><td><code>validateMessages()</code></td><td><code>&quot;Invalid message role: &lt;role&gt;&quot;</code></td></tr><tr><td>Response parsing failure</td><td><code>AnthropicResponseParser.parseResponse()</code></td><td>Re-throws original error after logging</td></tr><tr><td>Stream chunk parsing failure</td><td><code>AnthropicResponseParser.parseStreamingChunk()</code></td><td>Returns <code>null</code> after logging error</td></tr></tbody></table><p>Anthropic API errors are defined in <code>IAnthropicError</code> with types: <code>invalid_request_error</code>, <code>authentication_error</code>, <code>permission_error</code>, <code>not_found_error</code>, <code>rate_limit_error</code>, <code>api_error</code>, <code>overloaded_error</code>.</p><h2 id="class-contract-registry" tabindex="-1">Class Contract Registry <a class="header-anchor" href="#class-contract-registry" aria-label="Permalink to &quot;Class Contract Registry&quot;">​</a></h2><h3 id="interface-implementations" tabindex="-1">Interface Implementations <a class="header-anchor" href="#interface-implementations" aria-label="Permalink to &quot;Interface Implementations&quot;">​</a></h3><p>None. This package has no local interface implementations.</p><h3 id="inheritance-chains" tabindex="-1">Inheritance Chains <a class="header-anchor" href="#inheritance-chains" aria-label="Permalink to &quot;Inheritance Chains&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Base (Owner)</th><th>Derived</th><th>Location</th><th>Notes</th></tr></thead><tbody><tr><td><code>AbstractAIProvider</code> (agent-core)</td><td><code>AnthropicProvider</code></td><td><code>src/provider.ts</code></td><td>Primary provider implementation</td></tr></tbody></table><h3 id="cross-package-port-consumers" tabindex="-1">Cross-Package Port Consumers <a class="header-anchor" href="#cross-package-port-consumers" aria-label="Permalink to &quot;Cross-Package Port Consumers&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Port (Owner)</th><th>Adapter</th><th>Location</th></tr></thead><tbody><tr><td><code>AbstractAIProvider</code> (agent-core)</td><td><code>AnthropicProvider</code></td><td><code>src/provider.ts</code></td></tr></tbody></table><h2 id="test-strategy" tabindex="-1">Test Strategy <a class="header-anchor" href="#test-strategy" aria-label="Permalink to &quot;Test Strategy&quot;">​</a></h2><ul><li><strong>Current state</strong>: No test files exist in the package (<code>pnpm test</code> runs with <code>--passWithNoTests</code>).</li><li><strong>Recommended coverage areas</strong>: <ul><li>Unit tests for <code>AnthropicProvider</code> constructor validation (client vs apiKey vs executor).</li><li>Unit tests for message format conversion (<code>convertToAnthropicFormat</code>, <code>convertFromAnthropicResponse</code>), including tool call content-null invariant.</li><li>Unit tests for tool schema conversion (<code>convertToolsToAnthropicFormat</code>).</li><li>Unit tests for <code>AnthropicResponseParser.parseResponse()</code> covering text blocks, tool_use blocks, usage metadata, and error cases.</li><li>Unit tests for <code>AnthropicResponseParser.parseStreamingChunk()</code> covering all chunk types (<code>content_block_start</code>, <code>content_block_delta</code>, <code>content_block_stop</code>, <code>message_stop</code>).</li><li>Unit tests for <code>validateMessages()</code> edge cases.</li><li>Integration-style tests with mocked <code>@anthropic-ai/sdk</code> client for <code>chat()</code> and <code>chatStream()</code> flows.</li></ul></li><li><strong>Framework</strong>: Vitest (configured in workspace).</li><li><strong>Test commands</strong>: <code>pnpm test</code>, <code>pnpm test:watch</code>, <code>pnpm test:coverage</code>.</li></ul>',35)]))}const g=t(c,[["render",a]]);export{u as __pageData,g as default};
